fn is_palindrome(s: String) -> Bool:
    var cleaned = String("")
    for i in range(len(s)):
        var c = s[i]
        if c != " ":
            cleaned += c.lower()
    var n = len(cleaned)
    var l = 0
    var r = n - 1
    while l < r:
        if cleaned[l] != cleaned[r]:
            return False
        l += 1
        r -= 1
    return True
